const crypto = require('crypto');
function id(q) { return 'card-' + crypto.createHash('sha256').update(q.trim().toLowerCase()).digest('hex').slice(0,12); }
const cards = [];
function add(topicId, question, answer, explanation, difficulty, bloomLevel, tags) {
  cards.push({ id: id(question), question, answer, explanation, difficulty, bloomLevel, tags, topicId });
}

// PEDIATRICS - peds-asthma (10)
add('peds-asthma','A 6-year-old has recurring episodes of wheezing, cough, and shortness of breath that improve with salbutamol. Spirometry is not possible. How is pediatric asthma diagnosed?','Diagnosis based on: characteristic episodic symptoms + response to bronchodilator (≥12% FEV1 improvement) or positive bronchoprovocation test; trial of ICS can confirm diagnosis in children <5','CTS pediatric asthma guidelines: young children cannot reliably perform spirometry. For preschoolers (<5): clinical diagnosis based on recurrent wheeze, response to bronchodilator, exclusion of alternative diagnoses. ICS trial for 3 months; if response confirms asthma.',4,'apply',['pediatric asthma','diagnosis','bronchodilator response','ICS trial','pediatrics']);
add('peds-asthma','What is the first-line controller therapy for persistent asthma in children?','Low-dose inhaled corticosteroids (ICS) — e.g., fluticasone 88-176 μg/day or budesonide 200-400 μg/day; add LABA for step-up if needed (age ≥5 years)','CTS and GINA pediatric guidelines: ICS is the cornerstone of asthma control in children. Montelukast (LTRA) is an alternative but less effective. LABAs should always be used with ICS in children — never as monotherapy. Long-term ICS at recommended doses does not significantly affect growth.',2,'recall',['ICS','inhaled corticosteroids','pediatric asthma treatment','montelukast','pediatrics']);
add('peds-asthma','What are the management steps for a moderate acute asthma exacerbation in a 10-year-old in the ED?','SpO2 >94%, speaking in phrases: salbutamol 4-8 puffs via spacer q20min x3, ipratropium bromide 4-8 puffs q20min x3 (first hour), oral prednisone 1-2 mg/kg/day (max 40 mg) x3-5 days, supplemental O2','CPS/CTS guidelines: salbutamol + ipratropium combination in first hour reduces hospitalization. Oral corticosteroids equivalent to IV. Magnesium sulfate IV 40 mg/kg (max 2g) for severe exacerbations. Reassess after initial bronchodilators with oxygen saturation and clinical score (PRAM).',4,'apply',['acute asthma exacerbation','salbutamol','ipratropium','prednisone','pediatrics']);
add('peds-asthma','What is the PRAM (Pediatric Respiratory Assessment Measure) score?','PRAM: 0-12 scale assessing ScaleneO2 saturation, suprasternal retraction, scalene muscle activity, air entry, and wheeze; 0-3: mild, 4-7: moderate, 8-12: severe asthma exacerbation','CPS validated the PRAM score for Canadian pediatric ED management of asthma. Higher PRAM scores correlate with increased risk of hospitalization. Serial PRAM scores guide treatment decisions and discharge readiness. PRAM reliably reflects clinical response to bronchodilator therapy.',2,'recall',['PRAM score','asthma severity','pediatric asthma','ED assessment','pediatrics']);
add('peds-asthma','How is asthma control assessed in children using GINA criteria?','Well-controlled: daytime symptoms ≤2x/week, no night symptoms, SABA use ≤2x/week, no activity limitation; Partially controlled: 1-2 of these not met; Uncontrolled: ≥3 not met','CTS Canadian Pediatric Asthma Consensus Guidelines: assessment at every visit using patient/caregiver report of daytime symptoms, nighttime symptoms, activity limitation, and rescue inhaler use. Spirometry and FeNO add objective assessment. Step up if uncontrolled x4 weeks.',2,'recall',['asthma control','GINA criteria','pediatric asthma','step-up therapy','pediatrics']);
add('peds-asthma','What trigger avoidance measures are recommended for asthmatic children?','Environmental tobacco smoke (most important — parental smoking), dust mites (mattress/pillow covers), pet dander (remove pet if sensitized), mold remediation, exercise warm-up, avoid cold air, treat allergic rhinitis','CTS guidelines emphasize environmental control as part of asthma management. Second-hand smoke exposure doubles asthma exacerbation risk in children. Specific allergen immunotherapy (allergy shots) considered for allergic asthma sensitized to a single allergen.',2,'recall',['asthma triggers','tobacco smoke','allergen avoidance','environmental control','pediatrics']);
add('peds-asthma','What spacer/inhaler device should be used in children by age?','<4 years: MDI + spacer with face mask; 4-6 years: MDI + spacer with mouthpiece; >6 years: MDI + spacer (preferred) or DPI; nebulizers only for severe exacerbations or if spacer unavailable','CTS guidelines: spacers are as effective as nebulizers for asthma exacerbations in children when used correctly. All children should have an MDI + spacer for home use. Regular cleaning of spacer. Technique must be reviewed at every visit.',2,'recall',['spacer','inhaler technique','pediatric asthma','MDI','pediatrics']);
add('peds-asthma','What is the role of montelukast in pediatric asthma?','Montelukast (LTRA): second-line controller for mild persistent asthma; also useful for exercise-induced bronchoconstriction and allergic rhinitis comorbidity; less effective than ICS; Health Canada warns about neuropsychiatric side effects','CTS guidelines: LTRAs are alternatives to low-dose ICS for mild persistent asthma. Neuropsychiatric side effects (nightmares, behavioral changes, depression, suicidal ideation) require counseling and prompt reporting. Step-down to montelukast after ICS achieves control not recommended.',3,'recall',['montelukast','LTRA','pediatric asthma','neuropsychiatric effects','pediatrics']);
add('peds-asthma','What is bronchiolitis and how is it distinguished from asthma in infants?','Bronchiolitis: RSV-mediated viral lower respiratory tract infection in infants <24 months; first episode of wheeze + respiratory distress — NOT treated as asthma; supportive care only (O2, fluids)','CPS bronchiolitis guidelines: bronchodilators, corticosteroids, and antibiotics are NOT effective and should NOT be used for bronchiolitis. Diagnosis is clinical. Hospitalization for O2 requirement <90% or significant work of breathing. RSV monoclonal antibody (nirsevimab) now recommended for infants <6 months.',4,'analyze',['bronchiolitis','RSV','wheezing infant','asthma vs bronchiolitis','pediatrics']);
add('peds-asthma','What are the indications for referral to pediatric respirologist for asthma?','Uncontrolled asthma despite step 3 therapy (medium ICS + LABA), frequent exacerbations (≥2 steroid courses/year), ICU admission, uncertain diagnosis, suspicion of another etiology (GERD, laryngomalacia, foreign body, CF)','CTS guidelines recommend specialist referral for difficult asthma management. Comprehensive evaluation at a specialist level includes fractional exhaled nitric oxide (FeNO) measurement, bronchoprovocation testing, allergy testing, and investigation of asthma mimics.',2,'recall',['asthma referral','pediatric specialist','difficult asthma','pediatrics']);

// PEDIATRICS - peds-vaccines (10)
add('peds-vaccines','What is the routine childhood immunization schedule for Ontario/Canada at 2 months?','2 months: DTaP-IPV-Hib (diphtheria, tetanus, acellular pertussis, polio, Haemophilus influenzae b), pneumococcal conjugate (PCV13), meningococcal C (MenC-C), rotavirus (oral)','NACI (National Advisory Committee on Immunization) sets the Canadian immunization schedule. Provincial schedules vary slightly. All routine childhood vaccines are publicly funded. 2-month vaccines may cause fever and irritability — acetaminophen can be given.',2,'recall',['immunization schedule','2 months','DTaP','PCV13','pediatrics']);
add('peds-vaccines','What is the MMR vaccine and when is it given?','MMR (measles-mumps-rubella) live attenuated vaccine: first dose at 12-15 months, second dose at 18 months or 4-6 years — 95% efficacy for measles prevention','NACI: 2 doses of MMR achieve >97% protection. MMR is contraindicated in immunocompromised patients and pregnancy. Post-vaccination measles-like illness may occur 7-12 days after vaccination. Herd immunity threshold for measles: 95% vaccination coverage.',2,'recall',['MMR','measles','mumps','rubella','immunization','pediatrics']);
add('peds-vaccines','What is the HPV vaccine and who should receive it in Canada?','HPV vaccine (Gardasil 9 — 9-valent): 2 doses for ages 9-14 (≥6 months apart); 3 doses for ages 15-26 and immunocompromised; prevents 70-90% of cervical cancers, genital warts, oropharyngeal cancers','NACI recommends routine HPV vaccination for all adolescents at age 9-14, ideally before sexual debut. Gender-neutral programs implemented across Canada. Health Canada-approved up to age 45. HPV vaccination does not replace cervical cancer screening (Pap test).',2,'recall',['HPV vaccine','Gardasil','cervical cancer prevention','immunization','pediatrics']);
add('peds-vaccines','What vaccines are contraindicated in immunocompromised children?','Live attenuated vaccines are contraindicated: MMR, varicella (live), MMRV, BCG, oral typhoid, yellow fever, live oral rotavirus (relative), live influenza (FluMist) — inactivated vaccines are safe','CPS/NACI guidelines for immunocompromised children (cancer, HIV, immunosuppressive therapy): avoid live vaccines. Inactivated influenza vaccine recommended. Household contacts should receive inactivated flu vaccine. Varicella post-exposure prophylaxis with VZIG if exposed.',3,'apply',['immunocompromised','live vaccines','vaccination contraindications','pediatrics']);
add('peds-vaccines','What is the BCG vaccine and who receives it in Canada?','BCG (Bacillus Calmette-Guérin) TB vaccine: NOT routinely recommended in Canada; given at birth in high TB-prevalence countries; recommended in Canada only for infants in high-risk communities (First Nations, Inuit) with high TB rates','BCG is highly effective in preventing severe TB (meningitis, miliary TB) in infants but has variable efficacy against adult pulmonary TB. It causes false-positive TST reactions. NACI recommendation: selective use in high-risk groups; IGRA preferred for TB screening in BCG-vaccinated individuals.',3,'recall',['BCG','tuberculosis vaccine','NACI','Canada','pediatrics']);
add('peds-vaccines','What is the recommended catch-up vaccination strategy for a 5-year-old who has never been vaccinated?','Catch-up with all age-appropriate vaccines according to provincial schedule; minimum intervals between doses must be respected; measles and varicella can be given at any age to unvaccinated children','NACI catch-up schedules allow completion of missed vaccines with minimum intervals. Start from the beginning if vaccine series not previously started. Accelerated schedule respects minimum intervals between doses. Meningococcal ACWY, HPV, and adult Tdap when age-appropriate.',3,'apply',['catch-up vaccination','unvaccinated','immunization schedule','NACI','pediatrics']);
add('peds-vaccines','A parent refuses vaccines due to concerns about autism. How should this be addressed?','Acknowledge concerns respectfully; explain evidence disproving vaccine-autism link (Wakefield study retracted, multiple large studies); motivational interviewing approach; provide written resources; document discussion — do not dismiss or threaten','NACI and CPS strongly support routine immunization. The purported vaccine-autism link was based on a fraudulent, retracted study. Thiomersal has been removed from most childhood vaccines. Studies involving millions of children show no association between MMR and autism.',4,'apply',['vaccine hesitancy','autism myth','MMR','motivational interviewing','pediatrics']);
add('peds-vaccines','What vaccines are recommended at the 12-month well-child visit?','12 months: MMR, varicella, meningococcal C conjugate (MenC-C), PCV13 (4th dose); hepatitis A in provinces where included','Provincial immunization schedules vary. Most Canadian provinces have added hepatitis A vaccine to routine schedule. NACI recommends MenACWY for 12-month olds in provinces that use it as the primary MenC dose (replacing MenC-C). Review for any missed vaccines at each visit.',2,'recall',['12 month vaccines','MMR','varicella','meningococcal','pediatrics']);
add('peds-vaccines','What is the recommended influenza vaccine strategy for children in Canada?','Annual influenza vaccination for all children ≥6 months; children 6 months to 8 years receiving influenza vaccine for the first time need 2 doses (4 weeks apart) in the first season; LAIV (FluMist intranasal) preferred for 2-17 years if healthy (not appropriate for immunocompromised)','NACI recommends annual influenza vaccination for all Canadians starting at 6 months. LAIV has superior efficacy in children vs. inactivated vaccine. LAIV contraindicated in immunocompromised, severe asthma, salicylate therapy, pregnancy. Pharmacies can administer influenza vaccines in all provinces.',2,'recall',['influenza vaccine','annual immunization','LAIV','pediatric vaccine','pediatrics']);
add('peds-vaccines','What is vaccine-preventable disease reporting in Canada?','All vaccine-preventable diseases are nationally notifiable to PHAC; measles, mumps, rubella, pertussis, invasive Hib, invasive meningococcal/pneumococcal, polio, tetanus, and others — must be reported by physicians and laboratories','Notifiable disease reporting is provincially mandated. PHAC monitors national trends. Measles outbreaks: all cases require public health investigation and contact tracing. Imported measles from unvaccinated travelers drives most Canadian outbreaks. Vaccine-preventable disease outbreaks trigger catch-up campaigns.',2,'recall',['notifiable diseases','vaccine-preventable','PHAC','measles reporting','pediatrics']);

// OB/GYN - obgyn-obstetric-emerg (15)
add('obgyn-obstetric-emerg','A 32-week pregnant woman has sudden painless vaginal bleeding. She is hemodynamically stable. What is the differential diagnosis and approach?','Placenta previa (placenta overlying cervical os) most likely with painless bleeding — DO NOT perform digital vaginal exam; ultrasound to confirm; admit, cross-match, IV access','SOGC guidelines: placenta previa presents with painless vaginal bleeding in the 2nd-3rd trimester. Transvaginal ultrasound is safe and preferred for diagnosis. Betamethasone if <34 weeks (lung maturity). Delivery by cesarean section.',4,'apply',['placenta previa','antepartum hemorrhage','third trimester bleeding','SOGC','obgyn']);
add('obgyn-obstetric-emerg','A 34-week patient has sudden onset severe abdominal pain, rigid uterus, and vaginal bleeding. FHR shows late decelerations. What is the diagnosis and immediate management?','Placental abruption (premature separation of placenta); emergent delivery — cesarean for fetal distress; resuscitate mother with IV fluids, blood products; watch for DIC','SOGC guidelines: placental abruption is the most common cause of painful antepartum hemorrhage. Risk factors: hypertension, cocaine, trauma, prior abruption, smoking. Kleihauer-Betke test if Rh-negative (quantify fetal-maternal hemorrhage). DIC occurs in severe cases.',5,'analyze',['placental abruption','antepartum hemorrhage','fetal distress','DIC','obgyn']);
add('obgyn-obstetric-emerg','What are the SOGC criteria for diagnosing preeclampsia?','New-onset hypertension (≥140/90 mmHg) after 20 weeks + ≥1 of: proteinuria (≥300 mg/24h), end-organ dysfunction (thrombocytopenia <100,000, AKI, elevated LFTs, pulmonary edema, new-onset headache/visual symptoms), or IUGR','SOGC 2022 Hypertensive Disorders guidelines recommend using either proteinuria OR end-organ dysfunction (without proteinuria) to diagnose preeclampsia. Aspirin 100-162 mg/day started <16 weeks prevents preeclampsia in high-risk women.',3,'recall',['preeclampsia','SOGC','hypertension in pregnancy','proteinuria','obgyn']);
add('obgyn-obstetric-emerg','A 38-week patient with preeclampsia has BP 168/110, headache, visual changes, and platelet count of 88,000. What is the management?','Severe preeclampsia with features of severe disease; IV labetalol or hydralazine for acute BP control (target <160/110); IV magnesium sulfate for seizure prophylaxis; deliver','SOGC guidelines: BP ≥160/110 in pregnancy requires urgent treatment to prevent maternal stroke. Magnesium sulfate is the treatment of choice for preeclampsia seizure prophylaxis (MAGPIE trial). Definitive treatment is delivery. HELLP syndrome (Hemolysis, Elevated LFTs, Low Platelets) is a severe variant.',5,'analyze',['severe preeclampsia','magnesium sulfate','labetalol','delivery','obgyn']);
add('obgyn-obstetric-emerg','What is eclampsia and how is it managed?','Eclampsia: new onset grand mal seizure in preeclamptic patient; treat with IV magnesium sulfate (4-6g loading, then 1-2g/h maintenance), maintain airway, deliver after stabilization','SOGC guidelines: MgSO4 is superior to diazepam and phenytoin for eclampsia. Monitor for MgSO4 toxicity: loss of deep tendon reflexes (first sign), respiratory depression (antidote: calcium gluconate 1g IV). Magnesium continues for 24-48h postpartum.',5,'analyze',['eclampsia','magnesium sulfate','seizure in pregnancy','SOGC','obgyn']);
add('obgyn-obstetric-emerg','What is postpartum hemorrhage (PPH) and what are the 4Ts?','PPH: blood loss >500 mL (vaginal delivery) or >1000 mL (cesarean); 4Ts — Tone (uterine atony, most common 80%), Tissue (retained placenta), Trauma (lacerations), Thrombin (coagulopathy)','SOGC Active Management of Third Stage Labour (AMTSL) guidelines: oxytocin 10 IU IM immediately after delivery reduces PPH. PPH management: uterine massage, oxytocin infusion, uterotonics (carboprost, misoprostol, tranexamic acid), repair lacerations, manual removal retained placenta, surgical/interventional options.',4,'apply',['postpartum hemorrhage','4Ts','uterine atony','oxytocin','SOGC','obgyn']);
add('obgyn-obstetric-emerg','A pregnant woman at 12 weeks has severe nausea, vomiting, and is hemodynamically stable. hCG is markedly elevated and uterus is larger than dates. Ultrasound shows a snowstorm pattern. What is the diagnosis?','Hydatidiform mole (complete molar pregnancy); evacuate uterus by suction curettage, follow serial hCG until undetectable, contraception for 6-12 months, monitor for gestational trophoblastic neoplasia','Complete mole: 46XX (both paternal), no fetal tissue, higher risk of gestational trophoblastic neoplasia (15-20%). Partial mole: triploid, some fetal tissue. Risk of malignant transformation: serial hCG monitoring. Rh-negative mothers: Rh immunoglobulin. Chest X-ray for metastases.',4,'analyze',['molar pregnancy','gestational trophoblastic disease','hCG','snowstorm','obgyn']);
add('obgyn-obstetric-emerg','What is the management of cord prolapse?','Umbilical cord prolapse: immediately elevate presenting part manually (off cord), call for emergency C-section, position patient (knee-chest or Trendelenburg), do NOT push cord back in, fill bladder with 500 mL saline to elevate presenting part','SOGC cord prolapse guidelines: this is a category 1 emergency cesarean (immediate threat to life). Manual displacement of presenting part off the cord reduces compression. High flow O2 to mother. If delivery imminent, vaginal delivery may be attempted.',5,'analyze',['cord prolapse','obstetric emergency','cesarean','SOGC','obgyn']);
add('obgyn-obstetric-emerg','What is uterine rupture and what are the risk factors?','Uterine rupture: full-thickness tear of uterus usually at previous scar; sudden severe abdominal pain, loss of fetal station, fetal bradycardia, maternal hypotension; emergency laparotomy','SOGC VBAC guidelines: previous low transverse cesarean is primary risk factor for rupture during TOLAC. Risk ~0.5-1%. Signs: sudden cessation of contractions, acute abdominal pain, fetal heart rate abnormalities, maternal shock. Uterine repair or hysterectomy depending on severity.',5,'analyze',['uterine rupture','VBAC','TOLAC','obstetric emergency','SOGC','obgyn']);
add('obgyn-obstetric-emerg','What is the management of shoulder dystocia?','HELPERR mnemonic: Help (call for help), Episiotomy (consider), Legs (McRoberts maneuver — hyperflexion of maternal thighs), Pressure (suprapubic pressure), Enter (internal rotational maneuvers), Remove posterior arm, Roll patient to all-fours (Gaskin maneuver)','SOGC shoulder dystocia guidelines: McRoberts position with suprapubic pressure is the first-line maneuver (resolves 50% of cases). Avoid fundal pressure (worsens impaction). Episiotomy does not relieve bony obstruction but provides room for maneuvers. Clavicle fracture may be necessary as last resort.',5,'analyze',['shoulder dystocia','HELPERR','McRoberts','obstetric emergency','obgyn']);
add('obgyn-obstetric-emerg','What is HELLP syndrome and how does it present?','HELLP: Hemolysis (LDH >600), Elevated Liver enzymes (AST/ALT >2x normal), Low Platelets (<100,000) — presents with RUQ/epigastric pain, nausea, malaise in preeclampsia','SOGC guidelines: HELLP is a severe complication of preeclampsia. Delivery is the definitive treatment — typically indicated at ≥34 weeks or for maternal deterioration. <34 weeks: corticosteroids for fetal lung maturity then delivery. Monitor for DIC, hepatic hematoma/rupture.',4,'apply',['HELLP syndrome','preeclampsia','liver enzymes','platelets','obgyn']);
add('obgyn-obstetric-emerg','What are the indications for emergency cesarean section (Category 1)?','Category 1 (life-threatening): cord prolapse, uterine rupture, placental abruption with severe fetal distress, severe fetal bradycardia, maternal cardiac arrest — delivered within 30 minutes','SOGC/RCOG classification: Category 1 = immediate threat to maternal or fetal life (30 min DDI); Category 2 = maternal/fetal compromise, not immediately life-threatening (75 min); Category 3 = early delivery needed but no compromise; Category 4 = elective. Time to incision determines outcome.',4,'apply',['emergency cesarean','category 1','cord prolapse','uterine rupture','obgyn']);
add('obgyn-obstetric-emerg','A 28-year-old has sudden onset severe right lower quadrant pain with vaginal bleeding and a positive pregnancy test. What is the diagnosis and management?','Ectopic pregnancy; resuscitate with IV access and fluids; transvaginal ultrasound (empty uterus + adnexal mass); if unstable → emergent surgical treatment (salpingectomy); if stable → methotrexate if criteria met','SOGC ectopic guidelines: methotrexate criteria (stable, hCG <5000, no cardiac activity, ≤3.5cm mass). Salpingostomy vs. salpingectomy — salpingectomy preferred to prevent repeat ectopic. Rh-negative patients: Rh immunoglobulin. Serum hCG levels must decline appropriately.',5,'analyze',['ectopic pregnancy','methotrexate','salpingectomy','SOGC','obgyn']);
add('obgyn-obstetric-emerg','What is amniotic fluid embolism (AFE) and how is it treated?','AFE: catastrophic anaphylactoid reaction to amniotic fluid contents entering maternal circulation; sudden cardiorespiratory collapse, DIC, seizures; treatment: immediate resuscitation, CPR, correct DIC (blood products), deliver fetus','AFE is rare (1:20,000-40,000 deliveries) but has ~40-60% maternal mortality. No specific treatment — aggressive supportive care. SOGC guidelines: high-dose oxytocin for uterine atony, vasopressors for shock, massive transfusion protocol for DIC. Perimortem cesarean if no response to CPR within 4 minutes.',5,'analyze',['amniotic fluid embolism','AFE','DIC','maternal collapse','obgyn']);
add('obgyn-obstetric-emerg','What is the immediate management of a maternal cardiac arrest in the third trimester?','Left lateral displacement or manual uterine displacement during CPR; if no ROSC within 4 minutes: perimortem cesarean section at the resuscitation site (do NOT delay to transport) — improves both maternal and fetal outcomes','SOGC and advanced cardiac life support guidelines: standard CPR techniques apply, but left uterine displacement is critical to relieve aortocaval compression by the gravid uterus. Perimortem C-section relieves aortocaval compression and improves cardiac output in the mother.',5,'analyze',['maternal cardiac arrest','CPR in pregnancy','perimortem cesarean','SOGC','obgyn']);

// OB/GYN - obgyn-antenatal (15)
add('obgyn-antenatal','What are the components of the first prenatal visit in Canada?','Confirm pregnancy (urine hCG), dating ultrasound if uncertain, medical/obstetric history, blood tests (CBC, blood type/Rh, antibody screen, rubella immunity, VDRL, HBsAg, HIV, urine C&S, Pap if due), genetic counseling','SOGC Prenatal Care Guidelines recommend first prenatal visit ideally in first trimester (<10 weeks). Blood tests at first visit are standard. Pap test if due. Offer genetic screening (NIPT or maternal serum screening). Assess psychosocial risk factors and domestic violence.',2,'recall',['first prenatal visit','antenatal care','prenatal screening','SOGC','obgyn']);
add('obgyn-antenatal','What is the recommended folic acid supplementation in pregnancy?','0.4-1.0 mg/day for low-risk women starting 3 months before conception and continuing through first trimester (12 weeks); 4-5 mg/day for high-risk women (prior NTD, antiepileptics, diabetes, obesity)','SOGC guidelines: folic acid supplementation prevents neural tube defects (NTDs) by 50-70%. High-risk: personal or family history of NTDs, valproate or carbamazepine use (which antagonize folate). All women should take folic acid before attempting conception.',2,'recall',['folic acid','neural tube defects','pre-conceptional care','SOGC','obgyn']);
add('obgyn-antenatal','When is Rh immunoglobulin (RhIG, WinRho) indicated in pregnancy?','All Rh-negative women: prophylactically at 28 weeks (300 μg) AND within 72 hours postpartum if newborn is Rh-positive; also after any sensitizing event (threatened abortion, amniocentesis, antepartum hemorrhage, trauma)','SOGC RhIG guidelines: RhIG prevents maternal Rh alloimmunization which causes hemolytic disease of the fetus and newborn in future pregnancies. Kleihauer-Betke test quantifies fetomaternal hemorrhage to determine if additional doses needed. Cord blood Rh type must be checked at delivery.',3,'apply',['Rh immunoglobulin','WinRho','Rh alloimmunization','SOGC','obgyn']);
add('obgyn-antenatal','What is the first trimester screening for Down syndrome in Canada?','First trimester combined screening (FTCS): nuchal translucency measurement (10-14 weeks) + PAPP-A + free beta-hCG = Down syndrome detection rate 80-90% (with 5% screen-positive rate); NIPT (cell-free DNA) has >99% detection rate','SOGC prenatal screening guidelines recommend offering all women screening for aneuploidy. NIPT is preferred for high-risk patients (increased NT, age ≥40, prior affected pregnancy). NIPT positive result should be confirmed with diagnostic testing (CVS or amniocentesis) before termination of pregnancy.',3,'recall',['Down syndrome screening','NIPT','nuchal translucency','first trimester','SOGC','obgyn']);
add('obgyn-antenatal','What is gestational diabetes mellitus (GDM) and how is it screened for in Canada?','GDM: glucose intolerance first detected in pregnancy; screen all women at 24-28 weeks with 75g OGTT (Diabetes Canada) or 50g GCT followed by 100g GTT (traditional); diagnosis with ≥1 abnormal value on 75g OGTT','Diabetes Canada/SOGC recommend 75g OGTT at 24-28 weeks as primary screening test. GDM management: medical nutrition therapy first, then insulin if targets not met (fasting <5.3, 1h post-meal <7.8, 2h <6.7 mmol/L). Metformin is acceptable as second-line per SOGC.',3,'apply',['GDM','gestational diabetes','OGTT','screening','SOGC','obgyn']);
add('obgyn-antenatal','What is Group B Streptococcus (GBS) screening and when is intrapartum prophylaxis indicated?','Vaginal-rectal swab at 35-37 weeks; prophylaxis: IV penicillin G during labour if GBS-positive, prior GBS bacteriuria in current pregnancy, unknown GBS status with risk factors (fever in labour, ROM >18h, preterm labour <37 weeks)','SOGC GBS guidelines: penicillin G is first-line prophylaxis; ampicillin as alternative; clindamycin if PCN allergy (based on sensitivities). GBS-positive patients receiving intrapartum prophylaxis have <1% transmission rate. GBS prophylaxis starts with active labour.',3,'apply',['GBS','Group B Streptococcus','intrapartum prophylaxis','penicillin','SOGC','obgyn']);
add('obgyn-antenatal','What routine monitoring is recommended at each prenatal visit?','Blood pressure, urine dipstick (proteinuria), fundal height measurement (from 20 weeks), fetal heartbeat (Doppler from 10-12 weeks), fetal movements (from 28 weeks), weight, and review of concerns','SOGC prenatal visit schedule: monthly to 28 weeks, every 2 weeks to 36 weeks, weekly from 36 weeks until delivery. Fundal height: 1cm per week after 20 weeks correlates with gestational age ± 2 weeks. Routine urinalysis screens for proteinuria (preeclampsia) and infection.',1,'recall',['prenatal visit','routine monitoring','fundal height','blood pressure','obgyn']);
add('obgyn-antenatal','What is the anatomy ultrasound and when is it done?','Detailed anatomical ultrasound at 18-22 weeks assesses fetal growth, placental location, amniotic fluid, cervical length, and fetal anatomy (brain, face, spine, heart, abdomen, limbs)','SOGC recommends second-trimester anatomy ultrasound for all pregnancies. Identifies major structural anomalies (CHD, NTD, abdominal wall defects). Short cervix (<25mm at 20-24 weeks) increases preterm birth risk — consider cerclage or vaginal progesterone.',2,'recall',['anatomy ultrasound','20 weeks','fetal anatomy scan','SOGC','obgyn']);
add('obgyn-antenatal','What is preterm labour and how is it managed?','Preterm labour: regular contractions + cervical change before 37 weeks; management: corticosteroids (betamethasone 12mg IM q24h x2 doses) for fetal lung maturity at 24-34 weeks, tocolysis (nifedipine) to delay delivery by 48h for steroid effect, transfer to tertiary centre','SOGC guidelines: antenatal corticosteroids reduce RDS, IVH, and neonatal mortality. Tocolysis provides 24-48h delay (not long-term). Magnesium sulfate for neuroprotection at <32 weeks (reduces cerebral palsy). GBS prophylaxis for GBS-positive or unknown status in preterm labour.',4,'apply',['preterm labour','betamethasone','tocolysis','neonatal corticosteroids','SOGC','obgyn']);
add('obgyn-antenatal','A 36-week patient reports decreased fetal movement. What is the appropriate assessment?','Non-stress test (NST) to assess fetal wellbeing; reactive NST (2+ accelerations of ≥15 bpm for ≥15 sec in 20 min) = reassuring; non-reactive NST → biophysical profile (BPP)','SOGC guidelines: decreased fetal movement is associated with placental insufficiency and stillbirth. Kick counts: 6 movements in 2 hours is reassuring. Non-reactive NST requires BPP (5 parameters: NST, tone, movement, breathing, amniotic fluid volume). BPP score 8-10/10 = reassuring.',3,'apply',['fetal movement','NST','biophysical profile','fetal wellbeing','obgyn']);
add('obgyn-antenatal','What are the indications for antenatal corticosteroids (ACS)?','Antenatal corticosteroids (betamethasone 2x12mg IM 24h apart) indicated for anticipated preterm delivery at 24-34+6 weeks; consider at 34-36+6 weeks for late preterm; repeat course considered after 7+ days if still <34 weeks','SOGC guidelines: ACS reduce neonatal RDS, IVH, NEC, and mortality. Best effect when delivery occurs 24h-7 days after first dose. Tocolysis to delay delivery 48h allows completion of course. Does not improve outcome if given at ≥37 weeks.',3,'recall',['antenatal corticosteroids','betamethasone','preterm birth','fetal lung maturity','obgyn']);
add('obgyn-antenatal','What is the physiology of normal pregnancy changes that affect drug metabolism and dosing?','Increased blood volume (40%), GFR increases 40-50% (drug clearance), plasma albumin decreased (more free drug), gastric motility slowed (delayed absorption), hepatic CYP450 activity altered','Pharmacokinetic changes require dose adjustments in pregnancy. Increased GFR: renally-cleared drugs (ampicillin, LMWHs) require higher or more frequent dosing. Decreased albumin: highly protein-bound drugs (phenytoin) have increased free levels. Progesterone inhibits gastric motility.',3,'recall',['pregnancy pharmacokinetics','drug metabolism','GFR in pregnancy','obgyn']);
add('obgyn-antenatal','What are absolute contraindications to vaginal birth after cesarean (VBAC)?','Prior classical uterine incision (vertical upper segment), prior uterine rupture, more than 2 prior cesareans (relative contraindication), active genital herpes, placenta previa, cord prolapse','SOGC VBAC guidelines: low transverse cesarean scar does not preclude TOLAC (trial of labour after cesarean). VBAC success rate ~60-80%. Benefits: avoid major surgery, faster recovery. Risks: uterine rupture (0.5-1%). Continuous EFM required during TOLAC.',3,'apply',['VBAC','TOLAC','cesarean section','uterine rupture contraindications','obgyn']);
add('obgyn-antenatal','What is the impact of obesity on pregnancy outcomes?','Pre-pregnancy obesity (BMI ≥30) increases risk of: GDM, preeclampsia, preterm birth, cesarean delivery, stillbirth, neural tube defects, shoulder dystocia, maternal VTE, anesthetic complications','SOGC obesity guidelines: BMI should be measured and documented at first prenatal visit. GWG (gestational weight gain) targets: BMI 30-34.9: 5-9 kg; BMI ≥35: 0-6 kg. Bariatric surgery patients: monitor for nutritional deficiencies (iron, B12, folate). Thromboprophylaxis if additional risk factors.',3,'recall',['obesity in pregnancy','GDM','preeclampsia','gestational weight gain','obgyn']);
add('obgyn-antenatal','What is normal labor and what are the stages?','First stage: cervical dilation — latent phase (0-6 cm, variable duration), active phase (6-10 cm, ≥0.5 cm/h in nulliparous); Second stage: pushing to delivery (up to 3h with epidural, up to 2h without); Third stage: placental delivery (≤30 min)','SOGC Labour and Delivery guidelines: active phase of labour starts at 6 cm (updated from 4 cm in recent guidelines). Prolonged second stage: consider assisted delivery (forceps/vacuum). Active management of third stage: oxytocin, controlled cord traction, uterine massage.',2,'recall',['labour stages','cervical dilation','active phase','SOGC','obgyn']);

// OB/GYN - obgyn-gyn (15)
add('obgyn-gyn','What are the SOGC guidelines for cervical cancer screening (Pap test) in Canada?','Start at age 21 or 3 years after first sexual intercourse; Pap test every 3 years for ages 21-69; HPV primary testing every 5 years is being phased in — stop screening at age 69 (or after total hysterectomy for non-cancer indication)','SOGC/Canadian Cancer Society Cervical Cancer Screening Guidelines 2013: Pap testing every 3 years with normal results. HPV co-testing or primary HPV testing is being adopted in Canadian provinces for higher sensitivity. Women vaccinated against HPV should still have regular cervical screening.',2,'recall',['Pap test','cervical cancer screening','HPV testing','SOGC','obgyn']);
add('obgyn-gyn','A 45-year-old woman has heavy menstrual bleeding for 6 months. She is nulliparous, obese, and has irregular cycles. What is the priority investigation?','Endometrial biopsy (pipelle) to exclude endometrial hyperplasia or carcinoma; also pelvic ultrasound and CBC','SOGC AUB (Abnormal Uterine Bleeding) guidelines: endometrial biopsy indicated for AUB in women ≥40, or in younger women with risk factors for endometrial cancer (obesity, PCOS, chronic anovulation, tamoxifen use, Lynch syndrome). Hysteroscopy with directed biopsy is gold standard.',4,'apply',['abnormal uterine bleeding','endometrial biopsy','endometrial cancer','SOGC','obgyn']);
add('obgyn-gyn','What is the PALM-COEIN classification of abnormal uterine bleeding?','Structural (PALM): Polyp, Adenomyosis, Leiomyoma (fibroids), Malignancy/hyperplasia; Non-structural (COEIN): Coagulopathy, Ovulatory dysfunction, Endometrial, Iatrogenic, Not classified','FIGO PALM-COEIN classification guides investigation and management of AUB. Most common structural cause: fibroids (leiomyomas). Ovulatory dysfunction (anovulation): the most common non-structural cause. Treatment based on underlying etiology.',2,'recall',['PALM-COEIN','AUB','abnormal uterine bleeding','uterine fibroids','obgyn']);
add('obgyn-gyn','What is the treatment for uterine fibroids causing heavy menstrual bleeding?','Medical: tranexamic acid, NSAIDs, combined OCP, progestin IUD (levonorgestrel IUD); Procedural: uterine artery embolization (UAE), focused ultrasound; Surgical: myomectomy (fertility-preserving) or hysterectomy','Uterine fibroids (leiomyomas) are the most common benign pelvic tumors in women. Management depends on symptoms, fertility desires, and fibroid size/location. SOGC guidelines: LNG-IUS (Mirena) is highly effective for AUB from fibroids and adenomyosis.',3,'apply',['uterine fibroids','heavy menstrual bleeding','treatment','levonorgestrel IUD','SOGC','obgyn']);
add('obgyn-gyn','A 25-year-old woman has severe dysmenorrhea, deep dyspareunia, and pelvic pain. Ultrasound shows endometriomas bilaterally. Diagnosis and management?','Endometriosis; treat with combined OCP (first-line), progestins, GnRH agonists (leuprolide); surgery for severe cases or endometriomas; infertility treatment if planning pregnancy','SOGC endometriosis guidelines: medical treatment suppresses endometriosis but does not cure it; symptoms return when treatment is discontinued. Definitive diagnosis requires laparoscopy with biopsy. Endometriomas >4 cm: surgical drainage and ablation before IVF improves outcomes.',4,'apply',['endometriosis','dysmenorrhea','laparoscopy','GnRH agonist','SOGC','obgyn']);
add('obgyn-gyn','What is polycystic ovary syndrome (PCOS) and how is it diagnosed per Rotterdam criteria?','PCOS diagnosis requires 2 of 3: oligo/anovulation, clinical or biochemical hyperandrogenism, polycystic ovaries on ultrasound (≥12 follicles 2-9mm per ovary OR ovarian volume ≥10 mL) — exclusion of other causes','PCOS is the most common endocrinopathy in women of reproductive age (5-10%). Associated with insulin resistance, metabolic syndrome, T2DM, and endometrial cancer risk. Management: lifestyle modification, metformin, combined OCP for menstrual regulation and hyperandrogenism.',3,'apply',['PCOS','Rotterdam criteria','polycystic ovary','hyperandrogenism','obgyn']);
add('obgyn-gyn','A 65-year-old postmenopausal woman has a pelvic mass, elevated CA-125, and ascites. What is the diagnosis until proven otherwise and the management?','Ovarian cancer until proven otherwise; management: surgical staging and debulking (cytoreduction) by gynecologic oncologist, followed by platinum-based chemotherapy (carboplatin + paclitaxel)','Ovarian cancer has 5-year survival of 30-40% because most are diagnosed at advanced stage. Risk factors: BRCA1/2, nulliparity, endometriosis, HRT. No effective screening test. OCP use reduces lifetime ovarian cancer risk by 30-50%.',5,'analyze',['ovarian cancer','CA-125','debulking surgery','BRCA','obgyn']);
add('obgyn-gyn','What is the management of cervical cancer based on stage?','Stage IA1: cone biopsy or simple hysterectomy; Stage IA2-IIA: radical hysterectomy + pelvic LN dissection (or chemoradiation); Stage IIB-IVA: concurrent chemoradiation (cisplatin + radiotherapy)','Cervical cancer is HPV-related in >99% of cases. The most common histology is squamous cell carcinoma (75%), adenocarcinoma (20%). Sentinel lymph node biopsy increasingly used for early-stage cervical cancer. Bevacizumab added to chemotherapy for recurrent/metastatic disease.',4,'recall',['cervical cancer','staging','chemoradiation','HPV','obgyn']);
add('obgyn-gyn','What is the management of postmenopausal uterine bleeding?','Any postmenopausal bleeding requires immediate investigation with transvaginal ultrasound (endometrial thickness) and endometrial biopsy to exclude endometrial cancer — endometrial stripe >4mm warrants biopsy','SOGC and ACOG guidelines: endometrial cancer is the most common gynecological malignancy in Canada. Presenting symptom in 90%: postmenopausal bleeding. Endometrial biopsy (pipelle) should be performed regardless of ultrasound findings if clinical suspicion exists.',4,'apply',['postmenopausal bleeding','endometrial cancer','endometrial biopsy','transvaginal ultrasound','obgyn']);
add('obgyn-gyn','What is menopause and when does it occur?','Menopause: permanent cessation of menstruation, diagnosed retrospectively after 12 consecutive months of amenorrhea in a woman ≥45 years without other cause; average age in Canada: 51 years','SOGC menopause guidelines: FSH >30 IU/L and low estradiol support diagnosis. Perimenopause: irregular cycles, vasomotor symptoms (hot flashes), sleep disturbance, mood changes. Premature ovarian insufficiency (POI): menopause before age 40.',2,'recall',['menopause','FSH','perimenopause','vasomotor symptoms','obgyn']);
add('obgyn-gyn','What are the indications and contraindications for hormone replacement therapy (HRT/MHT)?','Indications: vasomotor symptoms (hot flashes), genitourinary syndrome of menopause (GSM), osteoporosis prevention, POI (premature ovarian insufficiency); Contraindications: breast cancer, endometrial cancer, unexplained vaginal bleeding, active liver disease, VTE or stroke history','SOGC Menopause Guidelines: MHT has the best benefit-risk profile for healthy women <60 or within 10 years of menopause (timing hypothesis). Combined estrogen + progestogen for women with intact uterus (prevents endometrial hyperplasia). Estrogen alone for post-hysterectomy.',3,'apply',['HRT','MHT','menopause treatment','hot flashes','SOGC','obgyn']);
add('obgyn-gyn','What is pelvic organ prolapse (POP) and how is it managed?','POP: descent of pelvic organs through pelvic floor (cystocele, rectocele, uterine prolapse); classified by POP-Q system; management: pelvic floor physiotherapy, pessary, or surgical repair','SOGC Urogynaecology guidelines: risk factors for POP: vaginal delivery, obesity, constipation, heavy lifting, advancing age, family history. Pelvic floor physiotherapy is first-line for mild-moderate prolapse. Pessaries provide non-surgical support. Surgical repair for severe or symptomatic POP.',3,'recall',['pelvic organ prolapse','cystocele','pessary','pelvic floor','obgyn']);
add('obgyn-gyn','What is the BRCA1/2 risk-reducing surgical strategy?','Risk-reducing salpingo-oophorectomy (RRSO) at 35-40 years (BRCA1) or 40-45 years (BRCA2) after childbearing — reduces ovarian cancer risk by 80-95%, breast cancer risk by 50%','SOGC hereditary gynecologic cancer guidelines: BRCA1/2 carriers should be referred to hereditary cancer programs. RRSO also induces surgical menopause — MHT until age 50 does not negate breast cancer risk reduction. Risk-reducing mastectomy (bilateral) reduces breast cancer risk by >90%.',4,'apply',['BRCA','RRSO','risk-reducing surgery','hereditary cancer','obgyn']);
add('obgyn-gyn','What are the symptoms and treatment of vulvovaginal candidiasis?','Vulval pruritus, burning, thick white cottage cheese discharge, dyspareunia; treat uncomplicated VVC with topical azole (clotrimazole, miconazole) or fluconazole 150 mg PO single dose','Most VVC is caused by Candida albicans. Recurrent VVC (≥4 episodes/year): investigate for underlying cause (diabetes, immunosuppression), treat with fluconazole weekly x6 months as maintenance. Azole-resistant Candida glabrata: intravaginal boric acid.',2,'recall',['vulvovaginal candidiasis','VVC','fluconazole','candida','obgyn']);
add('obgyn-gyn','What is the clinical presentation and treatment of ovarian torsion?','Ovarian torsion: sudden onset severe unilateral pelvic pain, nausea/vomiting, pelvic mass; Doppler ultrasound may show absent/reduced blood flow; emergency laparoscopy for detorsion — if viable, do not remove ovary','SOGC guidelines: ovarian torsion is a surgical emergency. Doppler absence does not confirm torsion (can have torsion with flow). Detorsion is preferred to oophorectomy — even if ovary appears necrotic, blood flow may return. Cystectomy at same time if ovarian cyst present.',4,'apply',['ovarian torsion','acute pelvic pain','laparoscopy','detorsion','obgyn']);

// OB/GYN - obgyn-contraception (10)
add('obgyn-contraception','What is the most effective reversible contraception method and how effective is it?','Intrauterine devices (LNG-IUS: 0.1-0.2% failure rate; copper IUD: 0.6-0.8% failure rate) and implants (etonogestrel implant: 0.05% failure rate) — all >99% effective as LARC (long-acting reversible contraception)','SOGC Contraception Guidelines: LARC methods (IUDs, implants) are most effective because they eliminate user error. Copper IUD is also the most effective emergency contraception (>99% if inserted within 5 days of unprotected intercourse).',2,'recall',['LARC','IUD','contraception','efficacy','SOGC','obgyn']);
add('obgyn-contraception','What are the absolute contraindications to combined oral contraceptive pills (COCPs)?','WHO Category 4: breastfeeding <6 weeks postpartum, hypertension ≥160/100, migraine with aura, stroke/TIA/DVT/PE history, ischemic heart disease, active liver disease/cancer, breast cancer, smoking ≥15 cigarettes/day age ≥35, major surgery with prolonged immobilization','SOGC/WHO MEC (Medical Eligibility Criteria) classify contraceptive use by condition. Category 4 = absolute contraindication; Category 3 = relative contraindication (risks usually outweigh benefits). Combined pills increase VTE and stroke risk in high-risk groups.',3,'recall',['OCP contraindications','combined pill','WHO MEC','stroke risk','obgyn']);
add('obgyn-contraception','What is emergency contraception and what options are available in Canada?','Emergency contraception (EC) options: 1) Levonorgestrel (Plan B One-Step) 1.5mg within 72h (reduced efficacy by 120h); 2) Ulipristal acetate (Ella) within 120h (more effective than LNG especially 72-120h); 3) Copper IUD within 120h (most effective >99%)','SOGC EC guidelines: levonorgestrel EC reduces pregnancy risk by 85-95% when used within 72h. Less effective with higher BMI (>75 kg). Ulipristal acetate is superior to LNG for women >75 kg. Copper IUD: most effective EC and provides ongoing contraception.',3,'apply',['emergency contraception','Plan B','ulipristal','copper IUD','SOGC','obgyn']);
add('obgyn-contraception','A 16-year-old requests contraception. What are the ethical and legal considerations in Canada?','Minors can consent to contraception without parental involvement in all Canadian provinces — physician must assess for capacity and coercion; maintain confidentiality','Canadian law and SOGC guidelines support provision of contraceptive care to mature minors without parental consent. Mature minor doctrine applies. Assess for coercion or abuse. Maintain confidentiality. Ontario\'s Personal Health Information Protection Act (PHIPA) protects adolescent health information.',3,'apply',['adolescent contraception','minors consent','confidentiality','mature minor','obgyn']);
add('obgyn-contraception','What is progestin-only contraception and when is it preferred over combined pills?','Progestin-only pill (POP), progestin IUD (LNG-IUS), progestin implant, DMPA injection; preferred when estrogen is contraindicated: breastfeeding, migraine with aura, VTE history, cardiovascular disease, smoking ≥35 years','SOGC guidelines: progestin-only methods do not contain estrogen and are safe in situations where estrogen is contraindicated. LNG-IUS (Mirena): most effective progestin-only method, also treats heavy menstrual bleeding and dysmenorrhea.',2,'recall',['progestin-only contraception','POP','LNG-IUS','estrogen contraindication','obgyn']);
add('obgyn-contraception','How does DMPA (Depo-Provera, medroxyprogesterone acetate) injection affect fertility?','DMPA (150 mg IM every 12 weeks): fertility return delayed up to 12-18 months after last injection; bone density temporarily reduced (reversible after discontinuation)','SOGC guidelines: DMPA is a highly effective (>99%) injectable contraceptive. Counseling about delayed fertility return is essential for women planning pregnancy within 12-18 months. Adolescents and women who may want pregnancy soon may prefer other methods.',3,'recall',['DMPA','Depo-Provera','fertility return','bone density','obgyn']);
add('obgyn-contraception','What is the mechanism and efficacy of copper IUD as an intrauterine device?','Copper IUD (e.g., Mona Lisa NT, IUD380): spermicidal (copper ions inhibit sperm motility), prevents fertilization, possible anti-implantation effect; 10-year efficacy >99%, failure rate 0.6-0.8%/year','SOGC IUD guidelines: copper IUD is inserted by trained providers during any phase of menstrual cycle or up to 5 days after unprotected sex (EC use). Side effects: heavier, more painful periods (opposite of LNG-IUS). No hormones — preferred by women who want hormone-free contraception.',2,'recall',['copper IUD','intrauterine device','contraception mechanism','heavy periods','obgyn']);
add('obgyn-contraception','A patient asks about sterilization (tubal ligation). What should the counseling include?','Tubal ligation is a permanent surgical method (assume irreversible); very effective (failure rate <0.5%); inform about failure risk (ectopic pregnancy risk if failure), alternatives (IUD equally effective and reversible), no protection against STIs','SOGC sterilization guidelines: patients should be counseled that sterilization is intended to be permanent. Regret rates: 5-26%, higher in women <30 and those having the procedure postpartum or after a recent pregnancy loss. Vasectomy for male partner is safer with lower failure rate.',3,'apply',['tubal ligation','sterilization','counseling','permanent contraception','obgyn']);
add('obgyn-contraception','What contraceptive options are safest for a breastfeeding mother 6 weeks postpartum?','Progestin-only methods (LNG-IUS, etonogestrel implant, POP, DMPA) or copper IUD — combined OCP contraindicated in first 6 weeks postpartum (breastfeeding and VTE risk)','SOGC Postpartum Contraception Guidelines: Breastfeeding provides some contraception (LAM: lactational amenorrhea method) — >98% effective if exclusive BF, amenorrheic, and <6 months postpartum. LARC methods (IUD, implant) can be inserted immediately postpartum (within 10 min of placental delivery) or delayed to 4 weeks.',3,'apply',['postpartum contraception','breastfeeding','LARC','progestin-only','SOGC','obgyn']);
add('obgyn-contraception','A woman with lupus (SLE) asks about contraception options. What is appropriate?','Active severe SLE: combined OCP is WHO category 3-4 (avoid if antiphospholipid antibodies, thrombocytopenia, or nephritis); progestin-only IUD or copper IUD are preferred','SOGC/WHO MEC guidelines for SLE: SLE without severe features and negative antiphospholipid antibodies — combined OCP may be used (category 2-3). SLE with antiphospholipid antibodies: combined OCP is contraindicated (category 4) due to VTE/thrombosis risk. LARC methods are safest.',4,'analyze',['SLE','lupus','contraception','antiphospholipid antibodies','obgyn']);

// PSYCHIATRY - psych-mood (15)
add('psych-mood','A 34-year-old has depressed mood, anhedonia, hypersomnia, weight gain, fatigue, and poor concentration for 6 weeks. She denies suicidal ideation. DSM-5 criteria met. First-line treatment?','Major Depressive Disorder (MDD); first-line: SSRI (escitalopram, sertraline, fluoxetine) or SNRI (venlafaxine, duloxetine) + psychotherapy (CBT is most evidence-based)','CANMAT (Canadian Network for Mood and Anxiety Treatments) MDD Guidelines: SSRIs/SNRIs are first-line pharmacotherapy. CBT is equally effective as medication for mild-moderate MDD and prevents relapse. Combined pharmacotherapy + psychotherapy is superior to either alone.',3,'apply',['major depressive disorder','SSRI','CBT','CANMAT','psychiatry']);
add('psych-mood','What are the DSM-5 diagnostic criteria for a major depressive episode?','≥5 of 9 symptoms for ≥2 weeks, including EITHER depressed mood OR anhedonia: SIGECAPS — Sleep (insomnia/hypersomnia), Interest (loss of), Guilt (worthlessness), Energy (fatigue), Concentration, Appetite (change), Psychomotor (retardation/agitation), Suicidality — causing significant impairment','MDD diagnosis requires: ≥5 symptoms, present most of the day nearly every day for ≥2 weeks, including depressed mood or anhedonia. Must cause significant distress/impairment. Rule out: substance use, medical conditions (hypothyroidism, Cushing), bereavement (can meet criteria for MDD).',2,'recall',['MDD criteria','SIGECAPS','DSM-5','major depressive episode','psychiatry']);
add('psych-mood','What is the approach when a patient with MDD fails to respond to the first SSRI after 6-8 weeks?','Switch to another SSRI or different class (SNRI, bupropion, mirtazapine), or augment (add lithium, atypical antipsychotic — quetiapine or aripiprazole, or T3)','CANMAT MDD guidelines: adequate trial is 4-8 weeks at therapeutic dose. Treatment failure: switch to another first-line agent or augment. Two failed trials = treatment-resistant depression (TRD). TRD options: lithium augmentation, atypical antipsychotic augmentation, ECT (most effective for TRD), esketamine nasal spray.',4,'apply',['treatment-resistant depression','SSRI failure','augmentation','CANMAT','psychiatry']);
add('psych-mood','What is the duration of antidepressant treatment for a first MDD episode?','Continue antidepressants for 6-12 months after full remission for a first episode; 2-3 years after 2 episodes; indefinite for 3+ episodes or high-risk features','CANMAT guidelines: premature discontinuation is the most common cause of relapse. Taper slowly over 4 weeks minimum when discontinuing (avoid discontinuation syndrome: FINISH — Flu-like symptoms, Insomnia, Nausea, Imbalance, Sensory disturbances, Hyperarousal). Patient education is critical.',2,'recall',['antidepressant duration','MDD relapse prevention','discontinuation syndrome','CANMAT','psychiatry']);
add('psych-mood','A 28-year-old woman has a history of MDD and asks about starting an antidepressant while planning to become pregnant. What is the appropriate approach?','Discuss risks of untreated depression vs. medication risks; SSRIs are preferred if pharmacotherapy needed (most safety data); paroxetine: avoid (cardiac defects); sertraline: lowest risk; neonatal adaptation syndrome may occur','CANMAT/SOGC guidelines: untreated maternal depression is associated with preterm birth, low birth weight, poor prenatal care. SSRI risk: neonatal adaptation syndrome (transient jitteriness, poor feeding) — not life-threatening. Persistent pulmonary hypertension of newborn: rare association with late pregnancy SSRI exposure.',4,'analyze',['antidepressants in pregnancy','SSRI','MDD in pregnancy','neonatal adaptation','SOGC','psychiatry']);
add('psych-mood','What is postpartum depression (PPD) and how is it different from baby blues?','Baby blues: mild mood fluctuations within 3-5 days of delivery, resolving within 2 weeks; PPD: meets MDD criteria within 12 months of delivery, requires treatment (psychotherapy, SSRIs)','SOGC/CANMAT guidelines recommend universal PPD screening (Edinburgh Postnatal Depression Scale, EPDS) at 6 weeks and 3 months postpartum. Score ≥13 suggests depression. SSRIs are safe with breastfeeding (sertraline has lowest breast milk transfer). Postpartum psychosis (rare 1-2/1000) is a medical emergency.',3,'apply',['postpartum depression','PPD','Edinburgh scale','EPDS','SOGC','psychiatry']);
add('psych-mood','What is bipolar disorder type I and how does it differ from type II?','Bipolar I: at least 1 manic episode (DSM-5: ≥1 week elevated/expansive/irritable mood + ≥3 DIGFAST symptoms); Bipolar II: recurrent MDD + hypomanic episodes (4-7 days, less severe, no psychosis or hospitalization needed)','CANMAT Bipolar Guidelines: bipolar I has episodes of mania that may require hospitalization. Bipolar II is often misdiagnosed as recurrent depression (hypomania missed). Antidepressant monotherapy is contraindicated in bipolar disorder — can trigger mania or mixed states.',3,'recall',['bipolar disorder','bipolar I','bipolar II','mania','hypomania','psychiatry']);
add('psych-mood','What is the DIGFAST mnemonic for manic symptoms?','Distractibility, Irresponsibility/Impulsivity, Grandiosity, Flight of ideas, Activity (increased goal-directed), Sleep (decreased need), Talkativeness (pressured speech)','DSM-5 manic episode: ≥7 days (or any duration if hospitalized) of elevated/expansive/irritable mood + ≥3 DIGFAST symptoms (≥4 if mood is irritable only). Psychotic features can occur in mania. Decreased need for sleep (not insomnia) is a key feature that distinguishes mania from MDD.',2,'recall',['DIGFAST','mania','manic episode','bipolar disorder','psychiatry']);
add('psych-mood','What are the first-line mood stabilizers for bipolar disorder?','Acute mania: lithium, valproate, or atypical antipsychotics (olanzapine, risperidone, quetiapine); Bipolar maintenance: lithium (most evidence), valproate, lamotrigine (especially for bipolar depression)','CANMAT Bipolar Guidelines: lithium is the gold standard for long-term bipolar management, reducing suicide risk by 6x. Lamotrigine is preferred for bipolar depression (less risk of switching to mania vs. antidepressants). Combination therapy is often required.',2,'recall',['mood stabilizers','lithium','valproate','lamotrigine','bipolar disorder','psychiatry']);
add('psych-mood','What is lithium toxicity and what are the signs?','Mild (1.5-2.0 mmol/L): tremor, polyuria, nausea; Moderate (2.0-2.5 mmol/L): confusion, ataxia, coarse tremor; Severe (>2.5 mmol/L): seizures, coma, permanent neurological damage — treat with IV hydration, hold lithium, dialysis for severe toxicity','Lithium has a narrow therapeutic index (0.6-1.2 mmol/L). Toxicity precipitants: dehydration, NSAIDs, ACEi/diuretics (reduce renal clearance), sodium depletion. Monitor: lithium level (12h post-dose), TSH, BMP, renal function every 6 months.',4,'apply',['lithium toxicity','lithium level','bipolar treatment','nephrotoxicity','psychiatry']);
add('psych-mood','What is dysthymia (persistent depressive disorder) and how is it managed?','Persistent depressive disorder: depressed mood most of the day, more days than not, for ≥2 years with ≥2 additional symptoms (insomnia/hypersomnia, low energy, poor concentration, hopelessness) — less severe than MDD but more chronic','CANMAT guidelines: dysthymia responds to the same treatments as MDD (SSRIs, SNRIs, CBT) but may require longer treatment duration. Double depression: MDD superimposed on dysthymia. Chronic depression has higher response rates with combined pharmacotherapy + psychotherapy.',2,'recall',['dysthymia','persistent depressive disorder','CANMAT','chronic depression','psychiatry']);
add('psych-mood','What is the role of electroconvulsive therapy (ECT) in mood disorders?','ECT is highly effective (80-90% response rate) for: treatment-resistant depression, severe MDD with psychosis, suicidal ideation with inability to wait for medications, bipolar depression, catatonia — fastest-acting treatment for severe MDD','CANMAT guidelines: ECT is the most effective treatment for TRD. Main side effect: short-term anterograde and retrograde memory impairment (usually reversible). Conducted under general anesthesia. Maintenance ECT for prevention of relapse. No absolute contraindications.',3,'recall',['ECT','electroconvulsive therapy','treatment-resistant depression','severe MDD','psychiatry']);
add('psych-mood','What screening tool is used for depression in Canada and what score indicates depression?','PHQ-9 (Patient Health Questionnaire-9): score 0-27; 5-9 = mild, 10-14 = moderate, 15-19 = moderately severe, ≥20 = severe depression; score ≥10 is the standard clinical cutoff for probable MDD','PHQ-9 is widely used in primary care and is validated in Canadian populations. CANMAT recommends routine depression screening with PHQ-2 (2 questions) and follow-up PHQ-9 if positive. EPDS for perinatal screening. PHQ-9 also used to monitor treatment response.',1,'recall',['PHQ-9','depression screening','CANMAT','severity scale','psychiatry']);
add('psych-mood','What are the indications for hospitalization in MDD?','Active suicidal ideation with plan/intent/means, psychotic depression, severe self-neglect (unable to care for self), inability to contract for safety, severe comorbidities requiring inpatient management','CANMAT guidelines: involuntary hospitalization under provincial mental health acts when patient poses serious harm to self or others and lacks capacity or refuses voluntary admission. Least restrictive alternative should be considered — intensive outpatient, crisis beds, ACT teams.',3,'apply',['hospitalization MDD','suicidal ideation','mental health act','inpatient psychiatry','psychiatry']);
add('psych-mood','What is seasonal affective disorder (SAD) and how is it treated?','SAD: recurrent depressive episodes with seasonal pattern (fall/winter onset, spring remission); treat with bright light therapy (10,000 lux for 30 min/morning), SSRIs, CBT','CANMAT guidelines: bright light therapy is first-line for SAD — equal efficacy to SSRIs with faster onset. Light therapy should be started in early fall before symptom onset. SSRIs (bupropion extended-release is specifically approved for SAD prevention). CBT adapted for SAD has lasting benefits.',3,'recall',['seasonal affective disorder','SAD','light therapy','SSRIs','psychiatry']);

